using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set OPENAI_API_KEY (or AZURE_OPENAI_ENDPOINT + key) env var
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools the agent can call
// ---------------------------------------------------------------------------
var notebook = new Notebook();

var searchTool = AIFunctionFactory.Create(
    (string query) =>
    {
        Console.WriteLine($"\n🔎  Searching the web for: \"{query}\" …");
        return WebSearchSimulator.Search(query);
    },
    "web_search",
    "Searches the web for the given query and returns a list of result snippets.");

var addNoteTool = AIFunctionFactory.Create(
    ([Description("A concise note capturing a key finding")] string note) =>
    {
        notebook.Add(note);
        Console.WriteLine($"📝  Note saved ({notebook.Count} total)");
        return $"Note saved. You now have {notebook.Count} note(s).";
    },
    "add_note",
    "Saves a research note for later use in the summary.");

var readNotesTool = AIFunctionFactory.Create(
    () =>
    {
        Console.WriteLine("📖  Reading all notes …");
        return notebook.Count == 0
            ? "No notes yet."
            : string.Join("\n", notebook.Notes.Select((n, i) => $"{i + 1}. {n}"));
    },
    "read_notes",
    "Returns all research notes collected so far.");

var tools = new AIFunction[] { searchTool, addNoteTool, readNotesTool };
var chatOptions = new ChatOptions { Tools = [.. tools] };

// ---------------------------------------------------------------------------
// Build the chat client with automatic function-calling support
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Prompt the user for a research topic
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬  AI Research Agent  🔬      ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic (or press Enter for default): ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
    topic = "recent breakthroughs in quantum computing";

Console.WriteLine($"\n🚀  Researching: \"{topic}\"\n");

// ---------------------------------------------------------------------------
// Agent loop – the system prompt instructs the model to search, take notes,
// then produce a final summary.
// ---------------------------------------------------------------------------
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the topic
        the user provides by following these steps:

        1. **Search** – call `web_search` two or three times with different
           queries to gather diverse information about the topic.
        2. **Take notes** – after each search, call `add_note` for every
           important finding so you don't forget anything.
        3. **Review** – call `read_notes` to review what you have collected.
        4. **Summarize** – produce a well-structured final summary in Markdown
           with sections, bullet points, and references. Do NOT call any more
           tools after you start the summary.

        Be thorough, accurate, and cite the sources you found.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}")
};

var response = await client.GetChatResponseAsync(messages, chatOptions);

// ---------------------------------------------------------------------------
// Print the final summary
// ---------------------------------------------------------------------------
Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("            📋  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n════════════════════════════════════════\n");
Console.WriteLine($"✅  Done — {notebook.Count} note(s) collected during research.\n");

// ===========================  Helper types  ================================

/// <summary>Simple in-memory notebook for collecting research findings.</summary>
class Notebook
{
    private readonly List<string> _notes = [];
    public IReadOnlyList<string> Notes => _notes;
    public int Count => _notes.Count;
    public void Add(string note) => _notes.Add(note);
}

/// <summary>
/// Simulates web search results so the app works without an external search
/// API key. Replace the body with a real API call (Bing, Google, Brave, etc.)
/// for production use.
/// </summary>
static class WebSearchSimulator
{
    public static string Search(string query)
    {
        var results = new[]
        {
            new
            {
                Title   = $"Latest developments in {query} – ScienceDaily",
                Snippet = $"Researchers have made significant strides in {query}. "
                        + "Recent studies published in Nature show promising advances "
                        + "that could reshape the field within the next decade.",
                Url     = "https://www.sciencedaily.com/example1"
            },
            new
            {
                Title   = $"{query}: A comprehensive overview – Wikipedia",
                Snippet = $"{query} encompasses multiple sub-fields and continues "
                        + "to evolve rapidly. Key areas include theoretical "
                        + "foundations, practical applications, and emerging "
                        + "interdisciplinary connections.",
                Url     = "https://en.wikipedia.org/example2"
            },
            new
            {
                Title   = $"Industry impact of {query} – TechCrunch",
                Snippet = $"Major tech companies are investing heavily in {query}. "
                        + "Market analysts predict the sector will grow "
                        + "substantially, driven by both public and private "
                        + "funding.",
                Url     = "https://techcrunch.com/example3"
            }
        };

        return JsonSerializer.Serialize(results, new JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

